import{_ as a,o as t,c as s,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"سؤالات متداول و عیب‌یابی (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"fa/faq.md","filePath":"fa/faq.md"}'),l={name:"fa/faq.md"};function c(i,e,r,d,n,m){return t(),s("div",null,[...e[0]||(e[0]=[o('<div dir="rtl"><h1 id="سؤالات-متداول-و-عیب‌یابی-faq" tabindex="-1"><i class="ph ph-question"></i> سؤالات متداول و عیب‌یابی (FAQ) <a class="header-anchor" href="#سؤالات-متداول-و-عیب‌یابی-faq" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-question&quot;&gt;&lt;/i&gt; سؤالات متداول و عیب‌یابی (FAQ)&quot;">​</a></h1><p>این بخش راه‌حل‌هایی برای مشکلات رایج و پاسخ‌هایی به سؤالاتی که اغلب در طول بهینه‌سازی WebGL پیش می‌آیند، ارائه می‌دهد.</p><h2 id="نصب-و-صحنه-دمو" tabindex="-1"><i class="ph ph-package"></i> نصب و صحنه دمو <a class="header-anchor" href="#نصب-و-صحنه-دمو" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-package&quot;&gt;&lt;/i&gt; نصب و صحنه دمو&quot;">​</a></h2><details class="details custom-block"><summary>پرسش: صحنه دمو را باز کردم، اما تمام متریال‌ها و اشیاء صورتی هستند!</summary><p><strong>پاسخ:</strong> پروژه شما از URP استفاده می‌کند، در حالی که صحنه دمو به‌طور پیش‌فرض برای BiRP تنظیم شده است. کافیست پکیج واقع در مسیر <code>WebAdaptivePerformance/Demo/Import Me (URP).unitypackage</code> را استخراج (Unpack) کنید. شیدرها به‌طور خودکار به‌روز خواهند شد.</p></details><details class="details custom-block"><summary>پرسش: افزونه را نصب کردم، اما از نظر بصری مطلقاً هیچ تغییری در بازی ایجاد نمی‌شود.</summary><p><strong>پاسخ:</strong> چک‌لیست زیر را بررسی کنید:</p><ul><li>آیا افزونه در Project Settings فعال است؟ آیا Scalerها اضافه و فعال شده‌اند؟</li><li>آیا گرافیک‌های Unity به‌طور پیش‌فرض روی حداکثر پیکربندی شده‌اند؟ اگر تنظیمات از قبل روی پایین‌ترین حالت باشند، افزونه چیزی برای کاهش نخواهد داشت.</li><li>ممکن است دستگاه به‌خوبی بار پردازشی را مدیریت می‌کند و FPS پایدار است. Prefab <code>Dashboard</code> را به صحنه اضافه کنید تا تصمیمات فعلی Indexer را مشاهده کنید.</li><li>اگر همه‌چیز به‌درستی پیکربندی شده اما باز هم تأثیری ندارد، با ما تماس بگیرید تا در عیب‌یابی به شما کمک کنیم.</li></ul></details><h2 id="وضوح-resolution-و-رابط-کاربری-ui" tabindex="-1"><i class="ph ph-monitor-play"></i> وضوح (Resolution) و رابط کاربری (UI) <a class="header-anchor" href="#وضوح-resolution-و-رابط-کاربری-ui" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-monitor-play&quot;&gt;&lt;/i&gt; وضوح (Resolution) و رابط کاربری (UI)&quot;">​</a></h2><details class="details custom-block"><summary>پرسش: وضوح صفحه تغییر نمی‌کند (Resolution Scaler غیرفعال است).</summary><p><strong>پاسخ:</strong> دو دلیل رایج عبارتند از:<br> ۱. اگر از <strong>BiRP</strong> و حالت <code>RenderTextureScaling</code> استفاده می‌کنید: آرایه <code>Target Tags</code> را در تنظیمات Scaler بررسی کنید. اگر دوربین بازی شما نام متفاوتی (غیر از <code>MainCamera</code>) دارد، باید آن تگ (Tag) را اضافه کنید. در غیر این صورت افزونه نمی‌تواند دوربین را پیدا کند.<br> ۲. حالت <code>NativeBrowserScaling</code> فقط در محیط رندر نهایی و بیلد شده‌ی WebGL کار می‌کند. این حالت درون Unity Editor هیچ کاری انجام نمی‌دهد.</p></details><details class="details custom-block"><summary>پرسش: وقتی FPS افت می‌کند، رابط کاربری من هم مخدوش/تار می‌شود!</summary><p><strong>پاسخ:</strong> بررسی کنید که در BiRP گزینه <code>RenderTextureScaling</code> انتخاب شده باشد. خود Canvas باید در حالت <code>Screen Space - Overlay</code> تنظیم شده باشد (یا باید از یک دوربین اختصاصی فقط برای UI استفاده کنید).</p></details><details class="details custom-block"><summary>پرسش: دکمه‌های استاندارد UI به‌خوبی کار می‌کنند، اما کلیک‌های ماوس (Raycastهای سفارشی) روی اشیاء سه‌بعدی اشتباه عمل می‌کنند.</summary><p><strong>پاسخ:</strong> رویدادهای استاندارد EventSystem توسط کامپوننت <code>WebScaledPhysicsRaycaster</code> به‌طور کامل اصلاح می‌شوند. اما اگر Raycastهای دستی را از طریق کد (<code>Camera.ScreenPointToRay()</code>) فراخوانی کنید، به دلیل اینکه وضوح صفحه با وضوح رندر شده مطابقت ندارد، در مختصات کلیک دچار خطا می‌شوند. برای این منظور، از متد افزونه ما استفاده کنید: <code>WebRaycasterUtility.TryComputeScaledRay()</code>.</p></details><h2 id="متریک‌ها-و-رفتار-سیستم" tabindex="-1"><i class="ph ph-chart-line-up"></i> متریک‌ها و رفتار سیستم <a class="header-anchor" href="#متریک‌ها-و-رفتار-سیستم" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-line-up&quot;&gt;&lt;/i&gt; متریک‌ها و رفتار سیستم&quot;">​</a></h2><details class="details custom-block"><summary>پرسش: کیفیت گرافیک به دلیل تأخیر کاهش یافت. حالا FPS دوباره بالا رفته است، اما گرافیک به حالت قبل برنمی‌گردد!</summary><p><strong>پاسخ:</strong> به‌احتمال قوی <strong>سیستم جریمه ضد یویو (Anti Yo-Yo Penalty System)</strong> فعال شده است. افزونه برای جلوگیری از ناپایداری (Quality flickering)، بهبودهای بصری را موقتاً مسدود کرده است.</p><ul><li>اگر می‌خواهید گرافیک سریع‌تر تثبیت شود، محدوده پارامتر <code>Penalty Lockout Duration</code> را کاهش دهید (مثلاً آن را روی ۱۰ ثانیه تنظیم کنید).</li><li>همچنین <code>Increase Cooldown</code> را بررسی کنید؛ ممکن است زمان انتظار آن خیلی زیاد تنظیم شده باشد.</li></ul></details><details class="details custom-block"><summary>پرسش: داشبورد دائماً وضعیت CPU Bottleneck (گلوگاه پردازنده) یا Unknown را نشان می‌دهد، با وجود اینکه صحنه خالی است.</summary><p><strong>پاسخ:</strong> فراموش نکنید که <code>Frame Timing Stats</code> را در تنظیمات Player فعال کنید. سپس بررسی کنید که مقدار <code>Application.targetFrameRate = -1</code> تنظیم شده باشد. با حذف محدودیت‌ها از نوسازی زمان، شما متریک‌ها را از کندی‌های ناشی از اجرای تابع <code>setTimeout</code> در مرورگر آزاد و رها می‌سازید.</p></details><details class="details custom-block"><summary>پرسش: کاراکتر من (یا اشیاء فیزیکی دیگر) به‌شدت پرش دارند یا لگ می‌زنند.</summary><p><strong>پاسخ:</strong> این یکی از اثرات جانبی ناشی از فعال‌سازی اجباری <code>Physics Step Scaler</code> است. این بخش مقدار پایه <code>Time.fixedDeltaTime</code> را تغییر می‌دهد تا در هنگام افت شدید عملکرد، از گیر کردن پردازنده جلوگیری کند. با فعال کردن فوری تنظیمات <code>Interpolate</code> (یا Extrapolate) موجود در تب کامپوننت <code>Rigidbody</code> کاراکتر در صحنه خود، انتقال‌های روان و بی‌نقص را تضمین کنید.</p></details><details class="details custom-block"><summary>پرسش: Scalerهای سایه (Shadow Scalers) فعال هستند، اما عملکرد همچنان در حال کاهش است و سایه‌ها دست‌نخورده باقی مانده‌اند.</summary><p><strong>پاسخ:</strong> این ماژول‌ها صرفاً وظیفه نظارت و کنترل سایه‌ها و نورپردازی‌های پویای Realtime را بر عهده دارند. اگر تنظیمات نورپردازی محیط از قبل محاسبه شده باشد (Baked/Lightmaps)، این ابزار هیچ‌گونه دخل و تصرفی روی آن نخواهد داشت.</p></details><h2 id="scalerهای-سفارشی-custom-scalers" tabindex="-1"><i class="ph ph-code"></i> Scalerهای سفارشی (Custom Scalers) <a class="header-anchor" href="#scalerهای-سفارشی-custom-scalers" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-code&quot;&gt;&lt;/i&gt; Scalerهای سفارشی (Custom Scalers)&quot;">​</a></h2><details class="details custom-block"><summary>پرسش: Scaler اختصاصی خودم در حالت Editor عالی کار می‌کند، اما در نسخه Build شده برای WebGL کاملاً ناپدید می‌شود!</summary><p><strong>پاسخ:</strong> در رویه‌های داخلی و استاندارد سیستم، هماهنگ‌کننده معماری IL2CPP اینطور برداشت می‌کند که کدهای شما بدون استفاده رها شده‌اند (&quot;dead code&quot;) و متعاقباً اقدام به حذف آن‌ها می‌کند. از این رو، حتماً ویژگی الزامی <code>[UnityEngine.Scripting.Preserve]</code> را در بالاترین سطر و قبل از تعریف کلاس اصلی Scaler سفارشیِ خود وارد کنید.</p></details></div>',1)])])}const h=a(l,[["render",c]]);export{p as __pageData,h as default};
